using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _pool;
    private readonly string[] _labels;

    public TicketsController(PredictionEnginePool<TicketInput, TicketPrediction> pool)
    {
        _pool = pool;

        // Extract label ordering from the model's Score column slot names
        var mlContext = new MLContext();
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        var model = mlContext.Model.Load(modelPath, out _);

        // Create a dummy prediction to access the output schema
        var dummyData = mlContext.Data.LoadFromEnumerable(new[] { new TicketInput() });
        var transformedSchema = model.GetOutputSchema(dummyData.Schema);
        var scoreCol = transformedSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreCol.GetSlotNames(ref slotNames);
        _labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }

    /// <summary>
    /// Predict the category of a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _pool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (int i = 0; i < _labels.Length && i < prediction.Score.Length; i++)
        {
            scores[_labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Scores = scores,
        });
    }
}

